const input = $input.first().json;
const body = input.body || input;

// Accept input from multiple sources:
// 1. Email Router (eMMA email forwarded from Gmail)
// 2. WhatsApp manual: 'Nova rfp [paste text]'
// 3. Direct webhook with rfp_text or rfp_name

const rfpText = String(body.rfp_text || body.text || body.email_body || '');
const rfpName = String(body.rfp_name || body.subject || body.rfx_name || 'Manual RFP');
const agency = String(body.agency || body.from || 'Unknown Agency');
const bpmId = String(body.bpm_id || body.rfx_id || '');
const deadline = String(body.deadline || body.end_date || '');
const commodity = String(body.commodity || body.main_commodity || '');
const source = String(body.source || 'manual');

if (!rfpText || rfpText.length < 10) {
  return [{ json: {
    error: true,
    message: 'No RFP content provided. Send rfp_text in the request body.',
    rfpName: rfpName
  }}];
}

const crypto = require('crypto');
const contentHash = crypto.createHash('md5').update(rfpText.substring(0, 500) + agency).digest('hex');

return [{ json: {
  rfpText: rfpText,
  rfpName: rfpName,
  agency: agency,
  bpmId: bpmId,
  deadline: deadline,
  commodity: commodity,
  source: source,
  contentHash: contentHash,
  timestamp: new Date().toISOString()
}}];

const https = require('https');
const input = $input.first().json;

if (input.error) {
  return [{ json: input }];
}

const SUPABASE_URL = 'raxpmeltyxmtiihxoxpa.supabase.co';
const SUPABASE_KEY = 'sb_secret_Jz8T31FHgqpfOrqijr1qtQ_HcbbZ8Nu';

// Check if we already processed this RFP
try {
  const result = await new Promise(function(resolve, reject) {
    const path = '/rest/v1/rfp_responses?content_hash=eq.' + input.contentHash + '&select=id,rfp_name,fit_score,kevin_decision';
    const req = https.request({
      hostname: SUPABASE_URL,
      port: 443,
      path: path,
      method: 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json'
      }
    }, function(res) {
      let d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
    });
    req.on('error', reject);
    req.end();
  });

  if (result.status === 200) {
    const existing = JSON.parse(result.body);
    if (existing && existing.length > 0) {
      const out = {};
      const keys = Object.keys(input);
      for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
      out.duplicate = true;
      out.existingRecord = existing[0];
      return [{ json: out }];
    }
  }
} catch(e) {
  // if dedup check fails, proceed anyway
}

const out = {};
const keys = Object.keys(input);
for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
out.duplicate = false;
return [{ json: out }];

const https = require('https');
const fs = require('fs');
const input = $input.first().json;

if (input.error || input.duplicate) {
  return [{ json: input }];
}

let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }

const founder = ctx.founder || {};
const entities = ctx.entities || {};
const naics = ctx.naics || {};

const AGENCY_WATCHLIST = [
  'mdsha', 'sha.maryland', 'state highway',
  'mta', 'transit', 'wmata',
  'baltimore city', 'baltimorecity',
  'bge', 'pepco', 'smeco', 'utility',
  'mdot', 'department of transportation',
  'mema', 'emergency management',
  'anne arundel', 'howard county', 'prince george',
  'nih', 'hhs', 'hrsa', 'cms',
  'fema', 'dhs', 'cisa',
  'umms', 'university of maryland', 'johns hopkins', 'medstar',
  'usda', 'rural development',
  'emma', 'maryland.gov'
];

const agencyLower = input.agency.toLowerCase();
const rfpLower = input.rfpText.toLowerCase();
const onWatchlist = AGENCY_WATCHLIST.some(function(w) {
  return agencyLower.indexOf(w) !== -1 || rfpLower.indexOf(w) !== -1;
});

const naicsList = (naics.registered || []).map(function(n) { return n.code + ' ' + n.description; }).join(', ');

const systemMessage = 'You are Nova, RFP Intelligence Agent for KAI-Netics. Analyze procurement opportunities and score them for fit. Be precise and decisive. Never fabricate contacts or requirements.';

const userMessage = 'Analyze this RFP/RFI for KAI-Netics.\n\n' +
  'RFP NAME: ' + input.rfpName + '\n' +
  'AGENCY: ' + input.agency + '\n' +
  'COMMODITY: ' + input.commodity + '\n' +
  'DEADLINE: ' + input.deadline + '\n\n' +
  'RFP CONTENT:\n' + input.rfpText.substring(0, 3000) + '\n\n' +
  'KAI-NETICS PROFILE:\n' +
  'Founder: ' + founder.name + ' | ' + (founder.credentials || []).join(', ') + '\n' +
  'Entity FP: ' + (entities.FP && entities.FP.name ? entities.FP.name : '') + '\n' +
  'Entity EAF: ' + (entities.EAF && entities.EAF.name ? entities.EAF.name : '') + '\n' +
  'NAICS Registered: ' + naicsList + '\n' +
  'Capabilities: Commercial drone operations (FAA Part 107), infrastructure inspection, cybersecurity consulting (CISSP), workforce development (EAF/CAKO), MONK hardware trust layer\n\n' +
  'Produce this EXACT format:\n\n' +
  'OPPORTUNITY SUMMARY:\n[Agency, value if stated, type RFI/RFP/RFQ, deadline]\n\n' +
  'NAICS ALIGNMENT:\n[Does it match 541519, 488190, or 541690? Yes/No with reason]\n\n' +
  'FIT SCORE: [0-100]\n\n' +
  'GO/NO-GO: [GO / NO-GO / AWARENESS]\n' +
  'GO = score 70+ and direct capability match\n' +
  'AWARENESS = score 30-69 OR agency on watchlist but low fit\n' +
  'NO-GO = score below 30 and agency not on watchlist\n\n' +
  'RATIONALE:\n[2-3 sentences explaining score]\n\n' +
  'COMPLIANCE FLAGS:\n[SAM.gov UEI required? Bonding? Insurance minimums? NDAA?]\n\n' +
  'TEAMING RECOMMENDATION:\n[Prime or sub? Suggested partners from: RK&K, JMT, Mobley & Brown]\n\n' +
  'WIN THEMES:\n1.\n2.\n3.\n\n' +
  'IMMEDIATE NEXT ACTIONS:\n1. [action | owner | deadline]\n2. [action | owner | deadline]\n3. [action | owner | deadline]';

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 2048,
  system: systemMessage,
  messages: [{ role: 'user', content: userMessage }]
});

const result = await new Promise(function(resolve, reject) {
  const req = https.request({
    hostname: 'api.anthropic.com',
    port: 443,
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': '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',
      'anthropic-version': '2023-06-01',
      'Content-Length': Buffer.byteLength(requestBody)
    }
  }, function(res) {
    let d = '';
    res.on('data', function(c) { d += c; });
    res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

let analysis = '';
try { analysis = JSON.parse(result.body).content[0].text || 'No response.'; } catch(e) { analysis = result.body.substring(0, 500); }

let fitScore = null;
const lines = analysis.split('\n');
for (let i = 0; i < lines.length; i++) {
  if (lines[i].toUpperCase().indexOf('FIT SCORE') !== -1) {
    const nums = lines[i].match(/\d+/);
    if (nums) { fitScore = parseInt(nums[0]); break; }
  }
}

let goNoGo = 'AWARENESS';
for (let i = 0; i < lines.length; i++) {
  const line = lines[i].toUpperCase();
  if (line.indexOf('GO/NO-GO') !== -1 || line.indexOf('GO NO GO') !== -1) {
    if (lines[i].indexOf('NO-GO') !== -1 || lines[i].indexOf('NO GO') !== -1) { goNoGo = 'NO-GO'; }
    else if (lines[i].indexOf('AWARENESS') !== -1) { goNoGo = 'AWARENESS'; }
    else if (lines[i].indexOf('GO') !== -1) { goNoGo = 'GO'; }
    break;
  }
}

// Override: if agency on watchlist and score >= 30, minimum AWARENESS
if (onWatchlist && fitScore !== null && fitScore >= 30 && goNoGo === 'NO-GO') {
  goNoGo = 'AWARENESS';
}

const out = {};
const keys = Object.keys(input);
for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
out.analysis = analysis;
out.fitScore = fitScore;
out.goNoGo = goNoGo;
out.onWatchlist = onWatchlist;
return [{ json: out }];

const https = require('https');
const input = $input.first().json;

if (input.error || input.duplicate) {
  return [{ json: input }];
}

// Only draft awareness response if AWARENESS or GO and on watchlist
const shouldDraft = (input.goNoGo === 'AWARENESS' || input.goNoGo === 'GO') && input.onWatchlist;

if (!shouldDraft) {
  const out = {};
  const keys = Object.keys(input);
  for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
  out.awarenessDraft = null;
  out.draftSkipped = true;
  return [{ json: out }];
}

const systemMessage = 'You are drafting a professional vendor awareness response on behalf of Kevin Alexander Smith, CEO of KAI-Netics (Kevin Alexander International LLC dba KAI-Netics, MWVOB minority-owned). Write in a professional, confident, brief tone. Not a sales pitch — a credentialed vendor making themselves known. Under 200 words total.';

const userMessage = 'Draft a vendor awareness response for this procurement:\n\n' +
  'Agency: ' + input.agency + '\n' +
  'RFP: ' + input.rfpName + '\n' +
  'Commodity: ' + input.commodity + '\n' +
  'Fit Score: ' + (input.fitScore || 'N/A') + '/100\n\n' +
  'Instructions:\n' +
  '1. Acknowledge the solicitation professionally\n' +
  '2. If fit is low (below 60): note KAI-Netics scope does not align with THIS requirement, but introduce capabilities\n' +
  '3. If fit is higher (60+): express interest and relevant qualifications\n' +
  '4. Plant a forward-looking hook for future drone/tech/cybersecurity requirements\n' +
  '5. Close with Kevin credentials: FAA Part 107 #5250157, CISSP, PMP, MWVOB\n\n' +
  'Format as a ready-to-send email body. Include subject line on first line prefixed with SUBJECT:';

const requestBody = JSON.stringify({
  model: 'claude-opus-4-6',
  max_tokens: 1024,
  system: systemMessage,
  messages: [{ role: 'user', content: userMessage }]
});

const result = await new Promise(function(resolve, reject) {
  const req = https.request({
    hostname: 'api.anthropic.com',
    port: 443,
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': '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',
      'anthropic-version': '2023-06-01',
      'Content-Length': Buffer.byteLength(requestBody)
    }
  }, function(res) {
    let d = '';
    res.on('data', function(c) { d += c; });
    res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

let draft = '';
try { draft = JSON.parse(result.body).content[0].text || ''; } catch(e) { draft = ''; }

const out = {};
const keys = Object.keys(input);
for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
out.awarenessDraft = draft;
out.draftSkipped = false;
return [{ json: out }];

const https = require('https');
const fs = require('fs');
const input = $input.first().json;

const SUPABASE_URL = 'raxpmeltyxmtiihxoxpa.supabase.co';
const SUPABASE_KEY = 'sb_secret_Jz8T31FHgqpfOrqijr1qtQ_HcbbZ8Nu';

if (input.error) {
  return [{ json: input }];
}

if (input.duplicate) {
  const out = {};
  const keys = Object.keys(input);
  for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
  out.supabaseLogged = false;
  out.supabaseNote = 'duplicate';
  return [{ json: out }];
}

// Save analysis to file
const safeAgency = input.agency.substring(0, 30).split('').map(function(c) {
  const code = c.charCodeAt(0);
  if ((code >= 65 && code <= 90) || (code >= 97 && code <= 122) || (code >= 48 && code <= 57)) return c;
  return '_';
}).join('');

const safeTime = input.timestamp.split(':').join('-').split('.').join('-');
const outputPath = '/data/Aidan_Outputs/Nova/RFP_' + safeTime + '_' + safeAgency + '.txt';
fs.mkdirSync('/data/Aidan_Outputs/Nova', { recursive: true });

let fileContent = 'NOVA RFP ANALYSIS\n';
fileContent += 'Agency: ' + input.agency + '\n';
fileContent += 'RFP: ' + input.rfpName + '\n';
fileContent += 'BPM ID: ' + input.bpmId + '\n';
fileContent += 'Deadline: ' + input.deadline + '\n';
fileContent += 'Fit Score: ' + (input.fitScore || 'N/A') + '\n';
fileContent += 'Decision: ' + input.goNoGo + '\n';
fileContent += 'Generated: ' + input.timestamp + '\n\n';
fileContent += '--- ANALYSIS ---\n' + (input.analysis || '') + '\n\n';
if (input.awarenessDraft) {
  fileContent += '--- AWARENESS DRAFT ---\n' + input.awarenessDraft + '\n';
}
fs.writeFileSync(outputPath, fileContent, 'utf8');

// Log to Supabase
const record = {
  rfp_name: input.rfpName,
  bpm_id: input.bpmId || null,
  agency: input.agency,
  commodity: input.commodity || null,
  deadline: input.deadline || null,
  fit_score: input.fitScore || null,
  go_no_go: input.goNoGo,
  awareness_draft: input.awarenessDraft || null,
  kevin_decision: 'PENDING',
  sent: false,
  content_hash: input.contentHash,
  source: input.source || 'manual'
};

let supabaseLogged = false;
try {
  const body = JSON.stringify(record);
  const result = await new Promise(function(resolve, reject) {
    const req = https.request({
      hostname: SUPABASE_URL,
      port: 443,
      path: '/rest/v1/rfp_responses',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Prefer': 'return=minimal',
        'Content-Length': Buffer.byteLength(body)
      }
    }, function(res) {
      let d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() { resolve({ status: res.statusCode }); });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
  supabaseLogged = result.status === 201 || result.status === 200;
} catch(e) {
  supabaseLogged = false;
}

const out = {};
const keys = Object.keys(input);
for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
out.outputPath = outputPath;
out.supabaseLogged = supabaseLogged;
return [{ json: out }];

const http = require('http');
const input = $input.first().json;

if (input.error) {
  const errMsg = 'NOVA ERROR: ' + input.message;
  const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: errMsg } });
  const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
  await new Promise(function(r) { const req = http.request(opts, function(res) { res.on('data', function(){}); res.on('end', r); }); req.on('error', r); req.write(msgBody); req.end(); });
  return [{ json: { success: false, error: input.message } }];
}

if (input.duplicate) {
  const dupMsg = 'NOVA: Duplicate RFP detected -- ' + input.rfpName + ' already processed. Decision: ' + (input.existingRecord && input.existingRecord.kevin_decision ? input.existingRecord.kevin_decision : 'PENDING');
  const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: dupMsg } });
  const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
  await new Promise(function(r) { const req = http.request(opts, function(res) { res.on('data', function(){}); res.on('end', r); }); req.on('error', r); req.write(msgBody); req.end(); });
  return [{ json: { success: true, duplicate: true } }];
}

const fitDisplay = input.fitScore !== null ? input.fitScore + '/100' : 'N/A';
const dbStatus = input.supabaseLogged ? '💾 Logged' : '⚠️ Log failed';

let whatsappMsg = 'NOVA RFP ANALYSIS\n\n';
whatsappMsg += 'RFP: ' + input.rfpName + '\n';
whatsappMsg += 'Agency: ' + input.agency + '\n';
if (input.bpmId) { whatsappMsg += 'BPM ID: ' + input.bpmId + '\n'; }
if (input.deadline) { whatsappMsg += 'Deadline: ' + input.deadline + '\n'; }
whatsappMsg += 'Fit Score: ' + fitDisplay + '\n';
whatsappMsg += 'Decision: ' + input.goNoGo + '\n';
whatsappMsg += dbStatus + '\n';

if (input.goNoGo === 'GO') {
  whatsappMsg += '\nACTION REQUIRED: High fit -- Jordan drafting capability statement\n';
  whatsappMsg += 'Reply: NOVA APPLY or NOVA PASS';
} else if (input.goNoGo === 'AWARENESS' && !input.draftSkipped) {
  whatsappMsg += '\nAwareness response drafted by Opus\n';
  whatsappMsg += 'Reply NOVA SEND to send, NOVA SKIP to pass';
} else {
  whatsappMsg += '\nLow fit -- no action required';
}

const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: whatsappMsg } });
const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
await new Promise(function(r) {
  const req = http.request(opts, function(res) { res.on('data', function(){}); res.on('end', r); });
  req.on('error', r); req.write(msgBody); req.end();
});

// If awareness draft exists, send it as a second WhatsApp message
if (input.awarenessDraft && !input.draftSkipped) {
  await new Promise(function(r) { setTimeout(r, 1500); });
  const draftPreview = 'OPUS DRAFT PREVIEW:\n\n' + input.awarenessDraft.substring(0, 1000);
  const draftBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: draftPreview } });
  const draftOpts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(draftBody) } };
  await new Promise(function(r) { const req = http.request(draftOpts, function(res) { res.on('data', function(){}); res.on('end', r); }); req.on('error', r); req.write(draftBody); req.end(); });
}

const cbBody = JSON.stringify({
  agent: 'Nova',
  rfpName: input.rfpName,
  agency: input.agency,
  fitScore: input.fitScore,
  goNoGo: input.goNoGo,
  supabaseLogged: input.supabaseLogged,
  timestamp: new Date().toISOString()
});
const cbOpts = { hostname: 'host.docker.internal', port: 5678, path: '/webhook/aidan-callback', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) } };
const cbReq = http.request(cbOpts, function(res) { res.on('data', function(){}); res.on('end', function(){}); });
cbReq.on('error', function(){});
cbReq.write(cbBody);
cbReq.end();

return [{ json: { success: true, agent: 'Nova', rfpName: input.rfpName, fitScore: input.fitScore, goNoGo: input.goNoGo, supabaseLogged: input.supabaseLogged } }];
